   262→// isPkgCvesDetactable checks whether CVEs is detactable with gost and oval from the result
   263→func isPkgCvesDetactable(r *models.ScanResult) bool {
   264→	if r.Release == "" {
   265→		logging.Log.Infof("r.Release is empty. Skip OVAL and gost detection")
   266→		return false
   267→	}
   268→
   269→	if r.ScannedVia == "trivy" {
   270→		logging.Log.Infof("r.ScannedVia is trivy. Skip OVAL and gost detection")
   271→		return false
   272→	}
   273→
   274→	switch r.Family {
   275→	case constant.FreeBSD, constant.ServerTypePseudo:
   276→		logging.Log.Infof("%s type. Skip OVAL and gost detection", r.Family)
   277→		return false
   278→	default:
   279→		if len(r.Packages)+len(r.SrcPackages) == 0 {
   280→			logging.Log.Infof("Number of packages is 0. Skip OVAL and gost detection")
   281→			return false
   282→		}
   283→		return true
   284→	}
   285→}
