   322→// FillCvesWithNvdJvn fills CVE detail with NVD, JVN
   323→func FillCvesWithNvdJvn(r *models.ScanResult, cnf config.GoCveDictConf, logOpts logging.LogOpts) (err error) {
   324→	cveIDs := []string{}
   325→	for _, v := range r.ScannedCves {
   326→		cveIDs = append(cveIDs, v.CveID)
   327→	}
   328→
   329→	client, err := newGoCveDictClient(&cnf, logOpts)
   330→	if err != nil {
   331→		return xerrors.Errorf("Failed to newGoCveDictClient. err: %w", err)
   332→	}
   333→	defer func() {
   334→		if err := client.closeDB(); err != nil {
   335→			logging.Log.Errorf("Failed to close DB. err: %+v", err)
   336→		}
   337→	}()
   338→
   339→	ds, err := client.fetchCveDetails(cveIDs)
   340→	if err != nil {
   341→		return xerrors.Errorf("Failed to fetchCveDetails. err: %w", err)
   342→	}
   343→
   344→	for _, d := range ds {
   345→		nvds, exploits, mitigations := models.ConvertNvdToModel(d.CveID, d.Nvds)
   346→		jvns := models.ConvertJvnToModel(d.CveID, d.Jvns)
   347→
   348→		alerts := fillCertAlerts(&d)
   349→		for cveID, vinfo := range r.ScannedCves {
   350→			if vinfo.CveID == d.CveID {
   351→				if vinfo.CveContents == nil {
   352→					vinfo.CveContents = models.CveContents{}
   353→				}
   354→				for _, con := range nvds {
   355→					if !con.Empty() {
   356→						vinfo.CveContents[con.Type] = []models.CveContent{con}
   357→					}
   358→				}
   359→				for _, con := range jvns {
   360→					if !con.Empty() {
   361→						found := false
   362→						for _, cveCont := range vinfo.CveContents[con.Type] {
   363→							if con.SourceLink == cveCont.SourceLink {
   364→								found = true
   365→								break
   366→							}
   367→						}
   368→						if !found {
   369→							vinfo.CveContents[con.Type] = append(vinfo.CveContents[con.Type], con)
   370→						}
   371→					}
   372→				}
   373→				vinfo.AlertDict = alerts
   374→				vinfo.Exploits = append(vinfo.Exploits, exploits...)
   375→				vinfo.Mitigations = append(vinfo.Mitigations, mitigations...)
   376→				r.ScannedCves[cveID] = vinfo
   377→				break
   378→			}
   379→		}
   380→	}
   381→	return nil
   382→}
