   384→func fillCertAlerts(cvedetail *cvemodels.CveDetail) (dict models.AlertDict) {
   385→	for _, nvd := range cvedetail.Nvds {
   386→		for _, cert := range nvd.Certs {
   387→			dict.USCERT = append(dict.USCERT, models.Alert{
   388→				URL:   cert.Link,
   389→				Title: cert.Title,
   390→				Team:  "uscert",
   391→			})
   392→		}
   393→	}
   394→
   395→	for _, jvn := range cvedetail.Jvns {
   396→		for _, cert := range jvn.Certs {
   397→			dict.JPCERT = append(dict.JPCERT, models.Alert{
   398→				URL:   cert.Link,
   399→				Title: cert.Title,
   400→				Team:  "jpcert",
   401→			})
   402→		}
   403→	}
   404→
   405→	return dict
   406→}
