   408→// detectPkgsCvesWithOval fetches OVAL database
   409→func detectPkgsCvesWithOval(cnf config.GovalDictConf, r *models.ScanResult, logOpts logging.LogOpts) error {
   410→	client, err := oval.NewOVALClient(r.Family, cnf, logOpts)
   411→	if err != nil {
   412→		return err
   413→	}
   414→	defer func() {
   415→		if err := client.CloseDB(); err != nil {
   416→			logging.Log.Errorf("Failed to close the OVAL DB. err: %+v", err)
   417→		}
   418→	}()
   419→
   420→	logging.Log.Debugf("Check if oval fetched: %s %s", r.Family, r.Release)
   421→	ok, err := client.CheckIfOvalFetched(r.Family, r.Release)
   422→	if err != nil {
   423→		return err
   424→	}
   425→	if !ok {
   426→		switch r.Family {
   427→		case constant.Debian:
   428→			logging.Log.Infof("Skip OVAL and Scan with gost alone.")
   429→			logging.Log.Infof("%s: %d CVEs are detected with OVAL", r.FormatServerName(), 0)
   430→			return nil
   431→		case constant.Windows, constant.FreeBSD, constant.ServerTypePseudo:
   432→			return nil
   433→		default:
   434→			return xerrors.Errorf("OVAL entries of %s %s are not found. Fetch OVAL before reporting. For details, see `https://github.com/vulsio/goval-dictionary#usage`", r.Family, r.Release)
   435→		}
   436→	}
   437→
   438→	logging.Log.Debugf("Check if oval fresh: %s %s", r.Family, r.Release)
   439→	_, err = client.CheckIfOvalFresh(r.Family, r.Release)
   440→	if err != nil {
   441→		return err
   442→	}
   443→
   444→	logging.Log.Debugf("Fill with oval: %s %s", r.Family, r.Release)
   445→	nCVEs, err := client.FillWithOval(r)
   446→	if err != nil {
   447→		return err
   448→	}
   449→
   450→	logging.Log.Infof("%s: %d CVEs are detected with OVAL", r.FormatServerName(), nCVEs)
   451→	return nil
   452→}
