   287→// DetectGitHubCves fetches CVEs from GitHub Security Alerts
   288→func DetectGitHubCves(r *models.ScanResult, githubConfs map[string]config.GitHubConf) error {
   289→	if len(githubConfs) == 0 {
   290→		return nil
   291→	}
   292→	for ownerRepo, setting := range githubConfs {
   293→		ss := strings.Split(ownerRepo, "/")
   294→		if len(ss) != 2 {
   295→			return xerrors.Errorf("Failed to parse GitHub owner/repo: %s", ownerRepo)
   296→		}
   297→		owner, repo := ss[0], ss[1]
   298→		n, err := DetectGitHubSecurityAlerts(r, owner, repo, setting.Token, setting.IgnoreGitHubDismissed)
   299→		if err != nil {
   300→			return xerrors.Errorf("Failed to access GitHub Security Alerts: %w", err)
   301→		}
   302→		logging.Log.Infof("%s: %d CVEs detected with GHSA %s/%s",
   303→			r.FormatServerName(), n, owner, repo)
   304→	}
   305→	return nil
   306→}
