   470→		return xerrors.Errorf("Failed to detect unfixed CVEs with gost: %w", err)
   471→	}
   472→
   473→	if r.Family == constant.Debian {
   474→		logging.Log.Infof("%s: %d CVEs are detected with gost",
   475→			r.FormatServerName(), nCVEs)
   476→	} else {
   477→		logging.Log.Infof("%s: %d unfixed CVEs are detected with gost",
   478→			r.FormatServerName(), nCVEs)
   479→	}
   480→	return nil
   481→}
   482→
   483→// DetectCpeURIsCves detects CVEs of given CPE-URIs
   484→func DetectCpeURIsCves(r *models.ScanResult, cpes []Cpe, cnf config.GoCveDictConf, logOpts logging.LogOpts) error {
   485→	client, err := newGoCveDictClient(&cnf, logOpts)
   486→	if err != nil {
   487→		return xerrors.Errorf("Failed to newGoCveDictClient. err: %w", err)
   488→	}
   489→	defer func() {
   490→		if err := client.closeDB(); err != nil {
   491→			logging.Log.Errorf("Failed to close DB. err: %+v", err)
   492→		}
   493→	}()
   494→
   495→	nCVEs := 0
   496→	for _, cpe := range cpes {
   497→		details, err := client.detectCveByCpeURI(cpe.CpeURI, cpe.UseJVN)
   498→		if err != nil {
   499→			return xerrors.Errorf("Failed to detectCveByCpeURI. err: %w", err)
   500→		}
   501→
   502→		for _, detail := range details {
   503→			advisories := []models.DistroAdvisory{}
   504→			if !detail.HasNvd() && detail.HasJvn() {
   505→				for _, jvn := range detail.Jvns {
   506→					advisories = append(advisories, models.DistroAdvisory{
   507→						AdvisoryID: jvn.JvnID,
   508→					})
   509→				}
   510→			}
   511→			maxConfidence := getMaxConfidence(detail)
   512→
   513→			if val, ok := r.ScannedCves[detail.CveID]; ok {
   514→				val.CpeURIs = util.AppendIfMissing(val.CpeURIs, cpe.CpeURI)
   515→				val.Confidences.AppendIfMissing(maxConfidence)
   516→				val.DistroAdvisories = advisories
   517→				r.ScannedCves[detail.CveID] = val
   518→			} else {
   519→				v := models.VulnInfo{
   520→					CveID:            detail.CveID,
   521→					CpeURIs:          []string{cpe.CpeURI},
   522→					Confidences:      models.Confidences{maxConfidence},
   523→					DistroAdvisories: advisories,
   524→				}
   525→				r.ScannedCves[detail.CveID] = v
   526→				nCVEs++
   527→			}
   528→		}
   529→	}
   530→	logging.Log.Infof("%s: %d CVEs are detected with CPE", r.FormatServerName(), nCVEs)
   531→	return nil
   532→}
   533→
   534→func getMaxConfidence(detail cvemodels.CveDetail) (max models.Confidence) {
   535→	if !detail.HasNvd() && detail.HasJvn() {
   536→		return models.JvnVendorProductMatch
   537→	} else if detail.HasNvd() {
   538→		for _, nvd := range detail.Nvds {
   539→			confidence := models.Confidence{}
   540→			switch nvd.DetectionMethod {
   541→			case cvemodels.NvdExactVersionMatch:
   542→				confidence = models.NvdExactVersionMatch
   543→			case cvemodels.NvdRoughVersionMatch:
   544→				confidence = models.NvdRoughVersionMatch
   545→			case cvemodels.NvdVendorProductMatch:
   546→				confidence = models.NvdVendorProductMatch
   547→			}
   548→			if max.Score < confidence.Score {
   549→				max = confidence
   550→			}
   551→		}
   552→	}
   553→	return max
   554→}
   555→
   556→// FillCweDict fills CWE
   557→func FillCweDict(r *models.ScanResult) {
   558→	uniqCweIDMap := map[string]bool{}
   559→	for _, vinfo := range r.ScannedCves {
   560→		for _, conts := range vinfo.CveContents {
   561→			for _, cont := range conts {
   562→				for _, id := range cont.CweIDs {
   563→					if strings.HasPrefix(id, "CWE-") {
   564→						id = strings.TrimPrefix(id, "CWE-")
   565→						uniqCweIDMap[id] = true
   566→					}
   567→				}
   568→			}
   569→		}
   570→	}
   571→
   572→	dict := map[string]models.CweDictEntry{}
   573→	for id := range uniqCweIDMap {
   574→		entry := models.CweDictEntry{
   575→			OwaspTopTens:       map[string]string{},
   576→			CweTopTwentyfives:  map[string]string{},
   577→			SansTopTwentyfives: map[string]string{},
   578→		}
   579→		if e, ok := cwe.CweDictEn[id]; ok {
   580→			fillCweRank(&entry, id)
   581→			entry.En = &e
   582→		} else {
   583→			logging.Log.Debugf("CWE-ID %s is not found in English CWE Dict", id)
   584→			entry.En = &cwe.Cwe{CweID: id}
   585→		}
   586→
   587→		if r.Lang == "ja" {
   588→			if e, ok := cwe.CweDictJa[id]; ok {
   589→				fillCweRank(&entry, id)
   590→				entry.Ja = &e
   591→			} else {
   592→				logging.Log.Debugf("CWE-ID %s is not found in Japanese CWE Dict", id)
   593→				entry.Ja = &cwe.Cwe{CweID: id}
   594→			}
   595→		}
   596→
   597→		dict[id] = entry
   598→	}
   599→	r.CweDict = dict
   600→	return
   601→}
   602→
   603→func fillCweRank(entry *models.CweDictEntry, id string) {
   604→	for year, ranks := range cwe.OwaspTopTens {
   605→		if rank, ok := ranks[id]; ok {
   606→			entry.OwaspTopTens[year] = rank
   607→		}
   608→	}
   609→	for year, ranks := range cwe.CweTopTwentyfives {
   610→		if rank, ok := ranks[id]; ok {
   611→			entry.CweTopTwentyfives[year] = rank
   612→		}
   613→	}
   614→	for year, ranks := range cwe.SansTopTwentyfives {
   615→		if rank, ok := ranks[id]; ok {
   616→			entry.SansTopTwentyfives[year] = rank
   617→		}
   618→	}
   619→}
