   321→	for _, line := range lines {
   322→		fields := strings.Fields(line)
   323→		if len(fields) < 4 {
   324→			continue
   325→		}
   326→		ip, _, err := net.ParseCIDR(fields[3])
   327→		if err != nil {
   328→			continue
   329→		}
   330→		if !ip.IsGlobalUnicast() {
   331→			continue
   332→		}
   333→		if ipv4 := ip.To4(); ipv4 != nil {
   334→			ipv4Addrs = append(ipv4Addrs, ipv4.String())
   335→		} else {
   336→			ipv6Addrs = append(ipv6Addrs, ip.String())
   337→		}
   338→	}
   339→	return
   340→}
