   549→func (l *base) detectServiceName(pid string) (string, error) {
   550→	cmd := fmt.Sprintf("systemctl status --quiet --no-pager %s", pid)
   551→	r := l.exec(cmd, noSudo)
   552→	if !r.isSuccess() {
   553→		return "", xerrors.Errorf("Failed to stat %s: %s", cmd, r)
   554→	}
   555→	return l.parseSystemctlStatus(r.Stdout), nil
   556→}
   557→
   558→func (l *base) parseSystemctlStatus(stdout string) string {
   559→	scanner := bufio.NewScanner(strings.NewReader(stdout))
   560→	scanner.Scan()
   561→	line := scanner.Text()
   562→	ss := strings.Fields(line)
   563→	if len(ss) < 2 || strings.HasPrefix(line, "Failed to get unit for PID") {
   564→		return ""
   565→	}
   566→	return ss[1]
   567→}
