  1197→func (l *base) parseLsOf(stdout string) map[string][]string {
  1198→	portPids := map[string][]string{}
  1199→	scanner := bufio.NewScanner(strings.NewReader(stdout))
  1200→	for scanner.Scan() {
  1201→		line := scanner.Text()
  1202→		if !strings.Contains(line, "LISTEN") {
  1203→			continue
  1204→		}
  1205→		ss := strings.Fields(line)
  1206→		if len(ss) < 10 {
  1207→			continue
  1208→		}
  1209→		pid, ipPort := ss[1], ss[8]
  1210→		portPids[ipPort] = util.AppendIfMissing(portPids[ipPort], pid)
  1211→	}
  1212→	return portPids
  1213→}
