   370→		if r := l.exec("test -f /opt/ds_agent/dsa_query", sudo); r.isSuccess() {
   371→			cmd := fmt.Sprintf(`/opt/ds_agent/dsa_query -c "GetAgentStatus" | grep %q`, dsFingerPrintPrefix)
   372→			r := l.exec(cmd, sudo)
