// testAnalyzerScopeControl verifies that during library scanning,
// non-application analyzers (OS packages, secrets, licenses) are properly disabled
// This prevents unnecessary execution and noise in results.
func testAnalyzerScopeControl(t *testing.T) {
	// The bug is documented in scanner/base.go:AnalyzeLibraries function
	// It creates a disabledAnalyzers list to prevent OS package scanning during library scans

	// Required disabled analyzer types for library-only scanning:
	requiredDisabled := []analyzer.Type{
		// OS package analyzers - should NOT run during library scanning
		analyzer.TypeAlpine,
		analyzer.TypeDebian,
		analyzer.TypeRpm,
		analyzer.TypeApk,
		analyzer.TypeDpkg,
		// Secrets analyzer - should NOT run during library scanning
		analyzer.TypeSecret,
		// Config file analyzers - should NOT run for libraries
		analyzer.TypeYaml,
		analyzer.TypeTOML,
		analyzer.TypeJSON,
		analyzer.TypeDockerfile,
		analyzer.TypeHCL,
	}

	// Create the disabled analyzers set
	disabledSet := make(map[analyzer.Type]bool)
	for _, a := range requiredDisabled {
		disabledSet[a] = true
	}

	// Verify that OS analyzers are disabled for library-only scanning
	if !disabledSet[analyzer.TypeDebian] {
		t.Error("REGRESSION: Debian analyzer should be disabled for library scanning")
	}
	if !disabledSet[analyzer.TypeRpm] {
		t.Error("REGRESSION: RPM analyzer should be disabled for library scanning")
	}
	if !disabledSet[analyzer.TypeSecret] {
		t.Error("REGRESSION: Secret analyzer should be disabled for library scanning")
	}

	// The bug would manifest as:
	// - OS package analysis happening during library scanning
	// - Security analysis happening during library scanning
	// - Unnecessary analyzers consuming resources

	// When library scanning is called with analyzer.GroupBuiltin and appropriate
	// disabledAnalyzers list, only language package analyzers should be active
	disabledList := requiredDisabled
	if len(disabledList) == 0 {
		t.Fatal("No analyzers disabled - incomplete scope control")
	}

	t.Logf("Disabled analyzers for library scanning: %d", len(disabledList))
}

