	if !disabledSet[analyzer.TypeDebian] {
		t.Error("REGRESSION: Debian analyzer should be disabled for library scanning")
	}
	if !disabledSet[analyzer.TypeRpm] {
		t.Error("REGRESSION: RPM analyzer should be disabled for library scanning")
	}
	if !disabledSet[analyzer.TypeSecret] {
		t.Error("REGRESSION: Secret analyzer should be disabled for library scanning")
	}

	// The bug would manifest as:
	// - OS package analysis happening during library scanning
	// - Security analysis happening during library scanning
	// - Unnecessary analyzers consuming resources

	// When library scanning is called with analyzer.GroupBuiltin and appropriate
	// disabledAnalyzers list, only language package analyzers should be active
	disabledList := requiredDisabled
	if len(disabledList) == 0 {
		t.Fatal("No analyzers disabled - incomplete scope control")
	}

	// Create analyzer with disabled types to verify API works
	anal := analyzer.NewAnalyzerGroup(analyzer.GroupBuiltin, disabledList)
	_ = anal

	t.Logf("Disabled analyzers for library scanning: %d", len(disabledList))
}

