func testPackageEcosystemDetection(t *testing.T) {
	// Check that analyzer types for PNPM and NuGet are properly configured
	// The bug is that PNPM is not imported and disabled analyzers may be incomplete

	// Test 1: Verify that analyzer.GroupBuiltin includes expected language package analyzers
	disabledAnalyzers := []analyzer.Type{
