		analyzer.TypeDpkg,
		analyzer.TypeRpm,
		analyzer.TypeApkCommand,
		analyzer.TypeYaml,
		analyzer.TypeTOML,
		analyzer.TypeJSON,
		analyzer.TypeDockerfile,
		analyzer.TypeHCL,
		analyzer.TypeSecret,
	}

	// Create an analyzer group with disabled OS package analyzers (library-only)
	// This should allow language package analyzers like PNPM and NuGet
	anal := analyzer.NewAnalyzerGroup(analyzer.GroupBuiltin, disabledAnalyzers)

	// analyzer.AnalyzerGroup is not a pointer, so we can't check nil
	// Just verify it was created without panicking
	_ = anal

	// The bug would be: if PNPM analyzer is not imported in scanner/base.go,
	// then pnpm-lock.yaml files won't be detected during library scanning
	// Similarly, if NuGet is not properly configured, .NET projects won't be detected

	// Verify that at least language package analyzers are available
