// TestPnpmLockfileDetection tests whether pnpm-lock.yaml files are detected
// during library scanning. This test documents the regression where PNPM
// is not supported.
func TestPnpmLockfileDetection(t *testing.T) {
	// The regression: pnpm-lock.yaml files are not in the LibraryMap
	// so they are not recognized as lockfiles during the auto-detect phase

	pnpmLockfileContent := `lockfileVersion: 5.4
specifiers:
  react: ^18.2.0
dependencies:
  react: 18.2.0
`

	// When scanner/base.go's scanLibraries() encounters a pnpm-lock.yaml file:
	// 1. It looks for the filename in models.LibraryMap
	// 2. If not found, it won't be recognized as a lockfile to scan
	// 3. Therefore, vulnerabilities in PNPM dependencies won't be detected

	t.Logf("REGRESSION: pnpm-lock.yaml content would be ignored during library scanning")
	t.Logf("Library scanning code would not recognize this as a lockfile: %d bytes",
		len(pnpmLockfileContent))

	// This is a regression because PNPM is a popular Node.js package manager
	// and projects using it should have their dependencies scanned
}

// TestNuGetEcosystemSupport tests whether .NET NuGet packages are properly detected
// This should work correctly if the nuget analyzer is properly imported
func TestNuGetEcosystemSupport(t *testing.T) {
	// NuGet support is documented in:
	// 1. scanner/base.go line 31: imports github.com/aquasecurity/fanal/analyzer/language/dotnet/nuget
	// 2. models/library.go lines 144-145: NuGetPkgsLock and NuGetPkgsConfig mappings

	nugetPackagesLockContent := `{
  "version": 2,
  "dependencies": {
    "Newtonsoft.Json": {
      "type": "package",
      "resolved": "1.0.0"
    }
  }
}
`

	// NuGet support should work for:
	// - packages.lock.json
	// - packages.config

	t.Logf("NuGet ecosystem support: packages.lock.json and packages.config should be detected")
	t.Logf("NuGet analyzer imported: yes (scanner/base.go line 31)")
	t.Logf("Content length: %d bytes", len(nugetPackagesLockContent))
}

// TestScanResultWithMissingEcosystems documents how missing PNPM support
// affects scan results
func TestScanResultWithMissingEcosystems(t *testing.T) {
	// Scenario: A project has both npm and pnpm dependencies
	// Lockfiles present:
	// - package-lock.json (npm)
	// - pnpm-lock.yaml (pnpm)

	// Expected behavior (what SHOULD happen):
	// - Both lockfiles detected
	// - Both scanned for vulnerabilities
	// - Results include vulnerabilities from both npm and pnpm dependencies

	// Actual behavior (regression):
	// - package-lock.json: DETECTED and scanned ✓
	// - pnpm-lock.yaml: NOT DETECTED, not scanned ✗

	t.Logf("REGRESSION: Projects with pnpm dependencies have incomplete vulnerability detection")
	t.Logf("Impact: Zero vulnerabilities reported for pnpm packages even if they have known CVEs")
	t.Logf("Affected users: Teams using pnpm package manager")
}

